def A000957_syt(N):
    for n in range(1, N+1):
        count = 0
        def bt(pos, top, bot, nt, nb):
            nonlocal count
            if pos == 2*n+1:
                if all(top[j]+1 != bot[j] for j in range(n)):
                    count += 1
                return
            if nt < n:
                top.append(pos); bt(pos+1,top,bot,nt+1,nb); top.pop()
            if nb < n and nb < nt:
                bot.append(pos); bt(pos+1,top,bot,nt,nb+1); bot.pop()
        bt(1,[],[],0,0)
        print(f"a({n+1}) = {count}")
